(function () {
  /* ── Config ──────────────────────────────────────────────────────────────── */
  const SUPABASE_ANON_KEY =
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVheGFzaHhwcXBpaG9ubnVoZHB4Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzI0NDk4MzMsImV4cCI6MjA4ODAyNTgzM30.j8n-puyJ6rKDMibSCxteJeWbVpI7xkxFux_njkHXlGg";

  const BASE = "https://eaxashxpqpihonnuhdpx.supabase.co/functions/v1";
  const GET_APPLICATIONS_URL = BASE + "/get-applications";
  const UPDATE_APPLICATION_URL = BASE + "/admin-update-application";
  const DELETE_APPLICATION_URL = BASE + "/admin-delete-application";
  const CREATE_APPLICATION_URL = BASE + "/admin-create-application";
  const UPDATE_EXPERIENCE_URL = BASE + "/admin-update-experience";
  const DELETE_EXPERIENCE_URL = BASE + "/admin-delete-experience";
  const CREATE_EXPERIENCE_URL = BASE + "/admin-create-experience";
  const MANAGE_SCHOOLS_URL = BASE + "/admin-manage-schools";
  const UPLOAD_APPLICATIONS_FILE_URL = BASE + "/admin-upload-applications";
  const UPLOAD_EXPERIENCES_FILE_URL = BASE + "/admin-upload-experiences";

  const PAGE_SIZE = 25;

  /* ── State ───────────────────────────────────────────────────────────────── */
  let allApplications = [];
  let allExperiences = [];
  let appPage = 1;
  let expPage = 1;

  /* ── SVG icons ───────────────────────────────────────────────────────────── */
  const ICON_EDIT = `<svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
      <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/>
      <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/>
    </svg>`;

  const ICON_DELETE = `<svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
      <polyline points="3 6 5 6 21 6"/>
      <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
      <path d="M10 11v6M14 11v6"/>
      <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/>
    </svg>`;

  const ICON_WARN = `<svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none"
      stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
      <polyline points="3 6 5 6 21 6"/>
      <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
      <path d="M10 11v6M14 11v6"/>
      <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/>
    </svg>`;

  /* ── Action button helpers ───────────────────────────────────────────────── */
  function makeActionBtn(iconSvg, cls, label) {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "adm-btn " + cls;
    btn.setAttribute("aria-label", label);
    btn.innerHTML = iconSvg;
    return btn;
  }

  function createActionButtons(app) {
    const wrap = document.createElement("div");
    wrap.style.cssText = "display:flex;align-items:center;gap:8px;";
    const editBtn = makeActionBtn(ICON_EDIT, "edit", "Edit");
    const deleteBtn = makeActionBtn(ICON_DELETE, "delete", "Delete");
    editBtn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      openAppModal(app);
    });
    deleteBtn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      openDeleteConfirm("application", app.id);
    });
    wrap.appendChild(editBtn);
    wrap.appendChild(deleteBtn);
    return wrap;
  }

  function createExperienceActionButtons(exp) {
    const wrap = document.createElement("div");
    wrap.style.cssText = "display:flex;align-items:center;gap:8px;";
    const editBtn = makeActionBtn(ICON_EDIT, "edit", "Edit");
    const deleteBtn = makeActionBtn(ICON_DELETE, "delete", "Delete");
    editBtn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      openExpModal(exp);
    });
    deleteBtn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      openDeleteConfirm("experience", exp.id);
    });
    wrap.appendChild(editBtn);
    wrap.appendChild(deleteBtn);
    return wrap;
  }

  /* ── Fetch ───────────────────────────────────────────────────────────────── */
  async function fetchApplications() {
    try {
      const response = await fetch(GET_APPLICATIONS_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: SUPABASE_ANON_KEY,
          Authorization: "Bearer " + SUPABASE_ANON_KEY,
        },
        body: JSON.stringify({
          user_id:
            typeof CURRENT_USER_ID !== "undefined" ? CURRENT_USER_ID : null,
          filters: {},
        }),
      });
      const result = await response.json();
      if (!response.ok) {
        console.error("Failed to load applications:", result);
        return [];
      }
      return result.applications || [];
    } catch (err) {
      console.error("Fetch applications error:", err);
      return [];
    }
  }

  /* ── Render applications table (paginated) ───────────────────────────────── */
  function renderApplicationsTable() {
    const rowsWrap = document.querySelector('[data-app-list="rows"]');
    if (!rowsWrap) return;
    const templateRow = rowsWrap.querySelector('[data-app-row="template"]');
    if (!templateRow) return;

    rowsWrap
      .querySelectorAll('[data-app-row="item"]')
      .forEach((r) => r.remove());

    const filteredApps = getFilteredApplicationsForCurrentSearch();
    const start = (appPage - 1) * PAGE_SIZE;
    const slice = filteredApps.slice(start, start + PAGE_SIZE);

    slice.forEach((app) => {
      const row = templateRow.cloneNode(true);
      row.setAttribute("data-app-row", "item");
      row.removeAttribute("hidden");
      row.style.display = "grid";

      const nameCell = row.querySelector('[data-cell="student-name"]');
      const aliasCell = row.querySelector('[data-cell="alias"]');
      const undergradCell = row.querySelector('[data-cell="undergrad"]');
      const actionsCell = row.querySelector('[data-cell="actions"]');

      if (nameCell) nameCell.textContent = app.pseudonym || "-";
      if (aliasCell) aliasCell.textContent = app.alias || "-";
      if (undergradCell)
        undergradCell.textContent = app.undergrad_institution || "-";
      if (actionsCell) {
        actionsCell.innerHTML = "";
        actionsCell.appendChild(createActionButtons(app));
      }

      rowsWrap.appendChild(row);
    });

    renderPagination("app", filteredApps.length, appPage, (p) => {
      appPage = p;
      renderApplicationsTable();
    });
  }

  /* ── Render experiences table (paginated) ────────────────────────────────── */
  function renderExperiencesTable() {
    const rowsWrap = document.querySelector('[data-exp-list="rows"]');
    if (!rowsWrap) return;
    const templateRow = rowsWrap.querySelector('[data-exp-row="template"]');
    if (!templateRow) return;

    rowsWrap
      .querySelectorAll('[data-exp-row="item"]')
      .forEach((r) => r.remove());

    const filteredExps = getFilteredExperiencesForCurrentSearch();
    const start = (expPage - 1) * PAGE_SIZE;
    const slice = filteredExps.slice(start, start + PAGE_SIZE);

    slice.forEach((exp) => {
      const row = templateRow.cloneNode(true);
      row.setAttribute("data-exp-row", "item");
      row.removeAttribute("hidden");
      row.style.display = "grid";

      const nameCell = row.querySelector('[data-cell="student-name"]');
      const typeCell = row.querySelector('[data-cell="experience-type"]');
      const titleCell = row.querySelector('[data-cell="title"]');
      const actionsCell = row.querySelector('[data-cell="actions"]');

      if (nameCell) nameCell.textContent = exp.student_name || "-";
      if (typeCell) typeCell.textContent = exp.experience_type || "-";
      if (titleCell) titleCell.textContent = exp.title || "-";
      if (actionsCell) {
        actionsCell.innerHTML = "";
        actionsCell.appendChild(createExperienceActionButtons(exp));
      }

      rowsWrap.appendChild(row);
    });

    renderPagination("exp", filteredExps.length, expPage, (p) => {
      expPage = p;
      renderExperiencesTable();
    });
  }

  /* ── Pagination controls ─────────────────────────────────────────────────── */
  function renderPagination(key, total, currentPage, onPageChange) {
    const containerId = "adm-pagination-" + key;
    let container = document.getElementById(containerId);

    if (!container) {
      container = document.createElement("div");
      container.id = containerId;
      container.className = "adm-pagination";
      const tableWrap = document.querySelector(
        key === "app" ? '[data-app-list="rows"]' : '[data-exp-list="rows"]',
      );
      if (tableWrap && tableWrap.parentElement)
        tableWrap.parentElement.appendChild(container);
    }

    const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));
    const start = Math.min((currentPage - 1) * PAGE_SIZE + 1, total);
    const end = Math.min(currentPage * PAGE_SIZE, total);

    container.innerHTML = `
        <span class="adm-pagination-info">
          Showing <strong>${start}–${end}</strong> of <strong>${total}</strong>
        </span>
        <div class="adm-pagination-controls">
          <button class="adm-page-btn" id="${containerId}-prev" ${currentPage <= 1 ? "disabled" : ""}>&#8592; Prev</button>
          <span style="font-size:13px;color:#374151;font-weight:600;">${currentPage} / ${totalPages}</span>
          <button class="adm-page-btn" id="${containerId}-next" ${currentPage >= totalPages ? "disabled" : ""}>Next &#8594;</button>
        </div>`;

    document
      .getElementById(containerId + "-prev")
      .addEventListener("click", () => onPageChange(currentPage - 1));
    document
      .getElementById(containerId + "-next")
      .addEventListener("click", () => onPageChange(currentPage + 1));
  }

  /* ── Modal scaffold ──────────────────────────────────────────────────────── */
  function buildModalOverlay(id) {
    let overlay = document.getElementById(id);
    if (overlay) return overlay;

    overlay = document.createElement("div");
    overlay.id = id;
    overlay.className = "adm-modal-overlay";
    overlay.addEventListener("click", (e) => {
      if (e.target === overlay) closeModal(overlay);
    });

    const modal = document.createElement("div");
    modal.className = "adm-modal";
    overlay.appendChild(modal);
    document.body.appendChild(overlay);
    return overlay;
  }

  function openModal(overlay) {
    overlay.classList.add("visible");
    document.body.style.overflow = "hidden";
  }

  function closeModal(overlay) {
    overlay.classList.remove("visible");
    document.body.style.overflow = "";
  }

  /* ── Application edit modal ──────────────────────────────────────────────── */
  function buildField(label, inputEl, fullWidth) {
    const wrap = document.createElement("div");
    wrap.className = "adm-field" + (fullWidth ? " full" : "");
    const lbl = document.createElement("label");
    lbl.className = "adm-label";
    if (label.endsWith(" *")) {
      lbl.textContent = label.slice(0, -2) + " ";
      const star = document.createElement("span");
      star.className = "req";
      star.textContent = "*";
      lbl.appendChild(star);
    } else {
      lbl.textContent = label;
    }
    wrap.appendChild(lbl);
    wrap.appendChild(inputEl);
    return wrap;
  }

  function inp(type, value, step, min, max) {
    const el = document.createElement("input");
    el.type = type || "text";
    el.className = "adm-input";
    el.value = value !== null && value !== undefined ? value : "";
    if (step !== undefined && step !== null) el.step = step;
    if (min !== undefined && min !== null) el.min = min;
    if (max !== undefined && max !== null) el.max = max;
    return el;
  }

  function sel(options, currentValue) {
    const el = document.createElement("select");
    el.className = "adm-select";
    options.forEach(([val, label]) => {
      const opt = document.createElement("option");
      opt.value = val;
      opt.textContent = label;
      if (val === currentValue) opt.selected = true;
      el.appendChild(opt);
    });
    return el;
  }

  function toggleField(label, checked) {
    const wrap = document.createElement("div");
    wrap.className = "adm-toggle-row full";
    const lbl = document.createElement("span");
    lbl.className = "adm-toggle-label";
    lbl.textContent = label;
    const chk = document.createElement("input");
    chk.type = "checkbox";
    chk.className = "adm-toggle";
    chk.checked = !!checked;
    wrap.appendChild(lbl);
    wrap.appendChild(chk);
    return { wrap, chk };
  }

  function sectionTitle(text) {
    const el = document.createElement("div");
    el.className = "adm-section-title";
    el.textContent = text;
    return el;
  }

  function openAppModal(app) {
    const overlay = buildModalOverlay("adm-app-modal");
    const modal = overlay.querySelector(".adm-modal");

    /* header */
    modal.innerHTML = `
        <div class="adm-modal-header">
          <span class="adm-modal-title">Edit Application</span>
          <button class="adm-modal-close" aria-label="Close">&times;</button>
        </div>`;
    modal
      .querySelector(".adm-modal-close")
      .addEventListener("click", () => closeModal(overlay));

    /* body */
    const body = document.createElement("div");
    body.className = "adm-modal-body";

    const grid = document.createElement("div");
    grid.className = "adm-form-grid";

    /* fields */
    const fields = {};

    const pseudonymInp = inp("text", app.pseudonym);
    const aliasInp = inp("text", app.alias);
    const undergradInp = inp("text", app.undergrad_institution);
    const stateInp = inp("text", app.state);
    const gpaInp = inp("number", app.gpa, "0.01", "0", "4.0");
    const mcatInp = inp("number", app.mcat, null, "472", "528");
    const gapYearsInp = inp("number", app.gap_years, null, "0");
    const interviewsInp = inp("number", app.interviews_count, null, "0");
    const acceptancesInp = inp("number", app.acceptances_count, null, "0");
    const scholarshipsInp = inp("number", app.scholarships_count, null, "0");
    const cycleStartInp = inp(
      "number",
      app.application_cycle_start_year,
      null,
      "2000",
      "2100",
    );
    const cycleEndInp = inp(
      "number",
      app.application_cycle_end_year,
      null,
      "2000",
      "2100",
    );
    const sesInp = inp("text", app.ses_disadvantaged);
    const statusSel = sel(
      [
        ["published", "Published"],
        ["draft", "Draft"],
        ["archived", "Archived"],
      ],
      app.status || "published",
    );

    fields.pseudonym = pseudonymInp;
    fields.alias = aliasInp;
    fields.undergrad_institution = undergradInp;
    fields.state = stateInp;
    fields.gpa = gpaInp;
    fields.mcat = mcatInp;
    fields.gap_years = gapYearsInp;
    fields.interviews_count = interviewsInp;
    fields.acceptances_count = acceptancesInp;
    fields.scholarships_count = scholarshipsInp;
    fields.application_cycle_start_year = cycleStartInp;
    fields.application_cycle_end_year = cycleEndInp;
    fields.ses_disadvantaged = sesInp;
    fields.status = statusSel;

    grid.appendChild(sectionTitle("Identity"));
    grid.appendChild(buildField("Pseudonym *", pseudonymInp));
    grid.appendChild(buildField("Alias *", aliasInp));
    grid.appendChild(sectionTitle("Academic"));
    grid.appendChild(buildField("Undergrad Institution *", undergradInp, true));
    grid.appendChild(buildField("State *", stateInp));
    grid.appendChild(buildField("GPA *", gpaInp));
    grid.appendChild(buildField("MCAT *", mcatInp));
    grid.appendChild(sectionTitle("Application Cycle"));
    grid.appendChild(buildField("Cycle Start Year *", cycleStartInp));
    grid.appendChild(buildField("Cycle End Year *", cycleEndInp));
    grid.appendChild(buildField("Gap Years", gapYearsInp));
    grid.appendChild(sectionTitle("Outcomes"));
    grid.appendChild(buildField("Interviews", interviewsInp));
    grid.appendChild(buildField("Acceptances", acceptancesInp));
    grid.appendChild(buildField("Scholarships", scholarshipsInp));
    grid.appendChild(sectionTitle("Profile"));
    grid.appendChild(buildField("SES Disadvantaged *", sesInp, true));
    grid.appendChild(buildField("Status", statusSel));

    /* boolean toggles */
    const toggleDefs = [
      ["on_time_application", "On-Time Application", app.on_time_application],
      ["reapplicant", "Reapplicant", app.reapplicant],
      ["first_generation", "First Generation", app.first_generation],
      ["military_service", "Military Service", app.military_service],
      [
        "institutional_actions",
        "Institutional Actions",
        app.institutional_actions,
      ],
    ];
    const toggleRefs = {};
    grid.appendChild(sectionTitle("Flags"));
    toggleDefs.forEach(([key, label, val]) => {
      const { wrap, chk } = toggleField(label, val);
      toggleRefs[key] = chk;
      grid.appendChild(wrap);
    });

    /* schools */
    const { el: schoolsEl, getSchools } = buildSchoolsSection(
      app.application_schools || [],
    );
    grid.appendChild(schoolsEl);

    body.appendChild(grid);
    modal.appendChild(body);

    /* footer */
    const footer = document.createElement("div");
    footer.className = "adm-modal-footer";
    const cancelBtn = document.createElement("button");
    cancelBtn.className = "adm-btn-cancel";
    cancelBtn.textContent = "Cancel";
    cancelBtn.addEventListener("click", () => closeModal(overlay));

    const saveBtn = document.createElement("button");
    saveBtn.className = "adm-btn-save";
    saveBtn.textContent = "Save Changes";
    saveBtn.addEventListener("click", async () => {
      /* required text fields */
      const requiredText = [
        pseudonymInp,
        aliasInp,
        undergradInp,
        stateInp,
        sesInp,
      ];
      let invalid = false;
      requiredText.forEach((el) => {
        if (!el.value.trim()) {
          el.style.borderColor = "#ef4444";
          if (!invalid) {
            el.focus();
            invalid = true;
          }
        } else {
          el.style.borderColor = "";
        }
      });

      /* required numeric fields (empty check only) */
      [cycleStartInp, cycleEndInp].forEach((el) => {
        if (el.value === "") {
          el.style.borderColor = "#ef4444";
          if (!invalid) {
            el.focus();
            invalid = true;
          }
        } else {
          el.style.borderColor = "";
        }
      });

      /* GPA: required, 0.00 – 4.00 */
      const gpaVal = parseFloat(gpaInp.value);
      if (gpaInp.value === "" || isNaN(gpaVal) || gpaVal < 0 || gpaVal > 4.0) {
        gpaInp.style.borderColor = "#ef4444";
        gpaInp.title = "GPA must be between 0.00 and 4.00";
        if (!invalid) {
          gpaInp.focus();
          invalid = true;
        }
      } else {
        gpaInp.style.borderColor = "";
        gpaInp.title = "";
      }

      /* MCAT: required, 472 – 528 */
      const mcatVal = parseInt(mcatInp.value, 10);
      if (
        mcatInp.value === "" ||
        isNaN(mcatVal) ||
        mcatVal < 472 ||
        mcatVal > 528
      ) {
        mcatInp.style.borderColor = "#ef4444";
        mcatInp.title = "MCAT must be between 472 and 528";
        if (!invalid) {
          mcatInp.focus();
          invalid = true;
        }
      } else {
        mcatInp.style.borderColor = "";
        mcatInp.title = "";
      }

      if (invalid) return;

      saveBtn.disabled = true;
      saveBtn.textContent = "Saving…";

      const payload = { id: app.id };
      Object.entries(fields).forEach(([k, el]) => {
        payload[k] =
          el.tagName === "SELECT"
            ? el.value
            : el.value === ""
              ? null
              : el.value;
      });
      Object.entries(toggleRefs).forEach(([k, chk]) => {
        payload[k] = chk.checked;
      });

      /* cast numerics */
      ["gpa"].forEach((k) => {
        if (payload[k] !== null) payload[k] = parseFloat(payload[k]);
      });
      [
        "mcat",
        "gap_years",
        "interviews_count",
        "acceptances_count",
        "scholarships_count",
        "application_cycle_start_year",
        "application_cycle_end_year",
      ].forEach((k) => {
        if (payload[k] !== null) payload[k] = parseInt(payload[k], 10);
      });

      const [ok, schoolsResult] = await Promise.all([
        callUpdate(UPDATE_APPLICATION_URL, payload),
        callManageSchools(app.id, getSchools()),
      ]);

      if (ok) {
        const idx = allApplications.findIndex((a) => a.id === app.id);
        if (idx !== -1) {
          allApplications[idx] = { ...allApplications[idx], ...payload };
          if (schoolsResult)
            allApplications[idx].application_schools =
              schoolsResult.schools || [];
        }
        renderApplicationsTable();
        closeModal(overlay);
      } else {
        saveBtn.disabled = false;
        saveBtn.textContent = "Save Changes";
        alert("Failed to save. Please try again.");
      }
    });

    footer.appendChild(cancelBtn);
    footer.appendChild(saveBtn);
    modal.appendChild(footer);

    openModal(overlay);
  }

  /* ── Experience edit modal ───────────────────────────────────────────────── */
  function openExpModal(exp) {
    const overlay = buildModalOverlay("adm-exp-modal");
    const modal = overlay.querySelector(".adm-modal");

    modal.innerHTML = `
        <div class="adm-modal-header">
          <span class="adm-modal-title">Edit Experience</span>
          <button class="adm-modal-close" aria-label="Close">&times;</button>
        </div>`;
    modal
      .querySelector(".adm-modal-close")
      .addEventListener("click", () => closeModal(overlay));

    const body = document.createElement("div");
    body.className = "adm-modal-body";
    const grid = document.createElement("div");
    grid.className = "adm-form-grid";

    const titleInp = inp("text", exp.title);
    const typeInp = inp("text", exp.experience_type);
    const categorySel = sel(
      [
        ["", "— Select type —"],
        ["additional", "Additional"],
        ["most_meaningful", "Most Meaningful"],
      ],
      exp.category || "",
    );
    const hoursInp = inp("number", exp.hours, null, "0");
    const sortInp = inp("number", exp.sort_order, null, "1");

    const descEl = document.createElement("textarea");
    descEl.className = "adm-textarea";
    descEl.value = exp.description || "";
    descEl.rows = 5;

    grid.appendChild(buildField("Title", titleInp, true));
    grid.appendChild(buildField("Category", typeInp));
    grid.appendChild(buildField("Type", categorySel));
    grid.appendChild(buildField("Hours", hoursInp));
    grid.appendChild(buildField("Sort Order", sortInp));
    grid.appendChild(buildField("Description", descEl, true));

    body.appendChild(grid);
    modal.appendChild(body);

    const footer = document.createElement("div");
    footer.className = "adm-modal-footer";

    const cancelBtn = document.createElement("button");
    cancelBtn.className = "adm-btn-cancel";
    cancelBtn.textContent = "Cancel";
    cancelBtn.addEventListener("click", () => closeModal(overlay));

    const saveBtn = document.createElement("button");
    saveBtn.className = "adm-btn-save";
    saveBtn.textContent = "Save Changes";
    saveBtn.addEventListener("click", async () => {
      saveBtn.disabled = true;
      saveBtn.textContent = "Saving…";

      const payload = {
        id: exp.id,
        title: titleInp.value || null,
        experience_type: typeInp.value || null,
        category: categorySel.value || null,
        hours: hoursInp.value !== "" ? parseInt(hoursInp.value, 10) : null,
        sort_order: sortInp.value !== "" ? parseInt(sortInp.value, 10) : null,
        description: descEl.value || null,
      };

      const ok = await callUpdate(UPDATE_EXPERIENCE_URL, payload);
      if (ok) {
        const idx = allExperiences.findIndex((e) => e.id === exp.id);
        if (idx !== -1)
          allExperiences[idx] = { ...allExperiences[idx], ...payload };
        renderExperiencesTable();
        closeModal(overlay);
      } else {
        saveBtn.disabled = false;
        saveBtn.textContent = "Save Changes";
        alert("Failed to save. Please try again.");
      }
    });

    footer.appendChild(cancelBtn);
    footer.appendChild(saveBtn);
    modal.appendChild(footer);
    openModal(overlay);
  }

  /* ── Delete confirm ──────────────────────────────────────────────────────── */
  function openDeleteConfirm(type, id) {
    let overlay = document.getElementById("adm-delete-confirm");
    if (!overlay) {
      overlay = document.createElement("div");
      overlay.id = "adm-delete-confirm";
      overlay.className = "adm-confirm-overlay";
      overlay.innerHTML = `
          <div class="adm-confirm-box">
            <div class="adm-confirm-icon">${ICON_WARN}</div>
            <div class="adm-confirm-title">Delete Record</div>
            <div class="adm-confirm-text">This action cannot be undone. Are you sure you want to delete this ${type}?</div>
            <div class="adm-confirm-actions">
              <button class="adm-btn-cancel" id="adm-delete-cancel">Cancel</button>
              <button class="adm-btn-danger" id="adm-delete-confirm-btn">Delete</button>
            </div>
          </div>`;
      overlay.addEventListener("click", (e) => {
        if (e.target === overlay) closeConfirm();
      });
      document.body.appendChild(overlay);
    }

    overlay.querySelector(".adm-confirm-text").textContent =
      `This action cannot be undone. Are you sure you want to delete this ${type}?`;

    const cancelBtn = overlay.querySelector("#adm-delete-cancel");
    const confirmBtn = overlay.querySelector("#adm-delete-confirm-btn");

    const fresh = confirmBtn.cloneNode(true);
    confirmBtn.parentNode.replaceChild(fresh, confirmBtn);
    fresh.disabled = false;
    fresh.textContent = "Delete";
    cancelBtn.onclick = closeConfirm;

    fresh.addEventListener("click", async () => {
      fresh.disabled = true;
      fresh.textContent = "Deleting…";

      const url =
        type === "application" ? DELETE_APPLICATION_URL : DELETE_EXPERIENCE_URL;
      const ok = await callDelete(url, id);

      if (ok) {
        if (type === "application") {
          allApplications = allApplications.filter((a) => a.id !== id);
          allExperiences = allExperiences.filter(
            (e) => e.application_id !== id,
          );
          if (appPage > Math.ceil(allApplications.length / PAGE_SIZE))
            appPage = Math.max(1, appPage - 1);
          if (expPage > Math.ceil(allExperiences.length / PAGE_SIZE))
            expPage = Math.max(1, expPage - 1);
          renderApplicationsTable();
          renderExperiencesTable();
        } else {
          allExperiences = allExperiences.filter((e) => e.id !== id);
          if (expPage > Math.ceil(allExperiences.length / PAGE_SIZE))
            expPage = Math.max(1, expPage - 1);
          renderExperiencesTable();
        }
        closeConfirm();
      } else {
        fresh.disabled = false;
        fresh.textContent = "Delete";
        alert("Failed to delete. Please try again.");
      }
    });

    overlay.classList.add("visible");
    document.body.style.overflow = "hidden";

    function closeConfirm() {
      overlay.classList.remove("visible");
      document.body.style.overflow = "";
    }
  }

  /* ── API helpers ─────────────────────────────────────────────────────────── */
  async function callUpdate(url, payload) {
    try {
      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: SUPABASE_ANON_KEY,
          Authorization: "Bearer " + SUPABASE_ANON_KEY,
        },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        const e = await res.json();
        console.error("Update error:", e);
        return false;
      }
      return true;
    } catch (err) {
      console.error("Update error:", err);
      return false;
    }
  }

  async function callDelete(url, id) {
    try {
      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: SUPABASE_ANON_KEY,
          Authorization: "Bearer " + SUPABASE_ANON_KEY,
        },
        body: JSON.stringify({ id }),
      });
      if (!res.ok) {
        const e = await res.json();
        console.error("Delete error:", e);
        return false;
      }
      return true;
    } catch (err) {
      console.error("Delete error:", err);
      return false;
    }
  }

  async function callCreate(url, payload) {
    try {
      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: SUPABASE_ANON_KEY,
          Authorization: "Bearer " + SUPABASE_ANON_KEY,
        },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        const e = await res.json();
        console.error("Create error:", e);
        return null;
      }
      return await res.json();
    } catch (err) {
      console.error("Create error:", err);
      return null;
    }
  }

  async function callManageSchools(applicationId, schools) {
    try {
      const res = await fetch(MANAGE_SCHOOLS_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          apikey: SUPABASE_ANON_KEY,
          Authorization: "Bearer " + SUPABASE_ANON_KEY,
        },
        body: JSON.stringify({ application_id: applicationId, schools }),
      });
      if (!res.ok) {
        const e = await res.json();
        console.error("Schools error:", e);
        return null;
      }
      return await res.json();
    } catch (err) {
      console.error("Schools error:", err);
      return null;
    }
  }

  /* ── Schools section builder ─────────────────────────────────────────────── */
  function buildSchoolsSection(initialSchools) {
    initialSchools = (initialSchools || [])
      .slice()
      .sort((a, b) => (a.sort_order || 0) - (b.sort_order || 0));

    const container = document.createElement("div");
    container.style.gridColumn = "1 / -1";

    /* header row */
    const hdr = document.createElement("div");
    hdr.style.cssText =
      "display:flex;align-items:center;justify-content:space-between;margin:14px 0 8px;";

    const lbl = document.createElement("span");
    lbl.style.cssText =
      "font-size:12px;font-weight:700;color:#374151;text-transform:uppercase;letter-spacing:.06em;";
    lbl.textContent = "Schools";

    const addBtn = document.createElement("button");
    addBtn.type = "button";
    addBtn.textContent = "+ Add School";
    addBtn.style.cssText =
      "background:#FFA25F;color:#fff;border:none;border-radius:6px;padding:4px 12px;font-size:12px;cursor:pointer;font-weight:600;";
    addBtn.addEventListener("click", () => addRow());

    hdr.appendChild(lbl);
    hdr.appendChild(addBtn);
    container.appendChild(hdr);

    /* bulk-paste area */
    const pasteWrap = document.createElement("div");
    pasteWrap.style.cssText =
      "display:flex;gap:8px;align-items:flex-start;margin-bottom:10px;";

    const pasteArea = document.createElement("textarea");
    pasteArea.placeholder =
      "Paste comma-separated school names here, then click Import…";
    pasteArea.rows = 2;
    pasteArea.style.cssText =
      "flex:1;font-size:12px;padding:6px 8px;border:1px solid #d1d5db;border-radius:6px;resize:vertical;line-height:1.4;font-family:inherit;";

    const importBtn = document.createElement("button");
    importBtn.type = "button";
    importBtn.textContent = "Import";
    importBtn.style.cssText =
      "background:#f3f4f6;border:1px solid #d1d5db;color:#374151;border-radius:6px;padding:6px 14px;font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap;flex-shrink:0;";

    importBtn.addEventListener("click", () => {
      const names = pasteArea.value
        .split(",")
        .map((s) => s.trim())
        .filter(Boolean);
      names.forEach((name) =>
        addRow({ school_name: name, school_type: "interviewed" }),
      );
      pasteArea.value = "";
      rowsWrap.scrollTop = rowsWrap.scrollHeight;
    });

    pasteWrap.appendChild(pasteArea);
    pasteWrap.appendChild(importBtn);
    container.appendChild(pasteWrap);

    /* column headings */
    const colHead = document.createElement("div");
    colHead.style.cssText =
      "display:grid;grid-template-columns:1fr 130px 32px;gap:8px;font-size:11px;font-weight:600;color:#9ca3af;padding:0 2px 6px;border-bottom:1px solid #f0f0f0;margin-bottom:6px;";
    colHead.innerHTML =
      "<span>School Name</span><span>Type</span><span></span>";
    container.appendChild(colHead);

    const rowsWrap = document.createElement("div");
    rowsWrap.style.cssText =
      "display:flex;flex-direction:column;gap:6px;max-height:260px;overflow-y:auto;padding-right:2px;";
    container.appendChild(rowsWrap);

    function addRow(school) {
      school = school || {};
      const row = document.createElement("div");
      row.className = "adm-school-row";
      row.style.cssText =
        "display:grid;grid-template-columns:1fr 130px 32px;gap:8px;align-items:center;";

      const nameInp = document.createElement("input");
      nameInp.type = "text";
      nameInp.className = "adm-input";
      nameInp.placeholder = "School name";
      nameInp.value = school.school_name || "";
      nameInp.style.cssText = "padding:5px 8px;font-size:12px;";

      const typeSel = document.createElement("select");
      typeSel.className = "adm-select";
      typeSel.style.cssText = "padding:5px 8px;font-size:12px;";
      [
        ["interviewed", "Interviewed"],
        ["accepted", "Accepted"],
        ["scholarship", "Scholarship"],
      ].forEach(([v, l]) => {
        const opt = document.createElement("option");
        opt.value = v;
        opt.textContent = l;
        if (v === (school.school_type || "interviewed")) opt.selected = true;
        typeSel.appendChild(opt);
      });

      const delBtn = document.createElement("button");
      delBtn.type = "button";
      delBtn.innerHTML = "&times;";
      delBtn.style.cssText =
        "background:#fff;border:1.5px solid #fca5a5;color:#ef4444;border-radius:4px;width:28px;height:28px;cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center;flex-shrink:0;";
      delBtn.addEventListener("click", () => row.remove());

      row.appendChild(nameInp);
      row.appendChild(typeSel);
      row.appendChild(delBtn);
      rowsWrap.appendChild(row);
    }

    initialSchools.forEach(addRow);

    function getSchools() {
      return Array.from(rowsWrap.querySelectorAll(".adm-school-row"))
        .map((row, i) => ({
          school_name: row.querySelector("input").value.trim(),
          school_type: row.querySelector("select").value,
          sort_order: i + 1,
        }))
        .filter((s) => s.school_name);
    }

    return { el: container, getSchools };
  }

  /* ── Add New Application modal ───────────────────────────────────────────── */
  function openNewAppModal() {
    const overlay = buildModalOverlay("adm-new-app-modal");
    const modal = overlay.querySelector(".adm-modal");

    modal.innerHTML = `
        <div class="adm-modal-header">
          <span class="adm-modal-title">Add New Application</span>
          <button class="adm-modal-close" aria-label="Close">&times;</button>
        </div>`;
    modal
      .querySelector(".adm-modal-close")
      .addEventListener("click", () => closeModal(overlay));

    const body = document.createElement("div");
    body.className = "adm-modal-body";
    const grid = document.createElement("div");
    grid.className = "adm-form-grid";

    const pseudonymInp = inp("text");
    const aliasInp = inp("text");
    const undergradInp = inp("text");
    const stateInp = inp("text");
    const gpaInp = inp("number", "", "0.01", "0", "4.0");
    const mcatInp = inp("number", "", null, "472", "528");
    const gapYearsInp = inp("number", 0, null, "0");
    const interviewsInp = inp("number", 0, null, "0");
    const acceptancesInp = inp("number", 0, null, "0");
    const scholarshipsInp = inp("number", 0, null, "0");
    const cycleStartInp = inp("number", "", null, "2000", "2100");
    const cycleEndInp = inp("number", "", null, "2000", "2100");
    const sesInp = inp("text");
    const statusSel = sel(
      [
        ["published", "Published"],
        ["draft", "Draft"],
        ["archived", "Archived"],
      ],
      "published",
    );

    const fields = {
      pseudonym: pseudonymInp,
      alias: aliasInp,
      undergrad_institution: undergradInp,
      state: stateInp,
      gpa: gpaInp,
      mcat: mcatInp,
      gap_years: gapYearsInp,
      interviews_count: interviewsInp,
      acceptances_count: acceptancesInp,
      scholarships_count: scholarshipsInp,
      application_cycle_start_year: cycleStartInp,
      application_cycle_end_year: cycleEndInp,
      ses_disadvantaged: sesInp,
      status: statusSel,
    };

    grid.appendChild(sectionTitle("Identity"));
    grid.appendChild(buildField("Pseudonym *", pseudonymInp));
    grid.appendChild(buildField("Alias *", aliasInp));
    grid.appendChild(sectionTitle("Academic"));
    grid.appendChild(buildField("Undergrad Institution *", undergradInp, true));
    grid.appendChild(buildField("State *", stateInp));
    grid.appendChild(buildField("GPA *", gpaInp));
    grid.appendChild(buildField("MCAT *", mcatInp));
    grid.appendChild(sectionTitle("Application Cycle"));
    grid.appendChild(buildField("Cycle Start Year *", cycleStartInp));
    grid.appendChild(buildField("Cycle End Year *", cycleEndInp));
    grid.appendChild(buildField("Gap Years", gapYearsInp));
    grid.appendChild(sectionTitle("Outcomes"));
    grid.appendChild(buildField("Interviews", interviewsInp));
    grid.appendChild(buildField("Acceptances", acceptancesInp));
    grid.appendChild(buildField("Scholarships", scholarshipsInp));
    grid.appendChild(sectionTitle("Profile"));
    grid.appendChild(buildField("SES Disadvantaged *", sesInp, true));
    grid.appendChild(buildField("Status", statusSel));

    const toggleDefs = [
      ["on_time_application", "On-Time Application", false],
      ["reapplicant", "Reapplicant", false],
      ["first_generation", "First Generation", false],
      ["military_service", "Military Service", false],
      ["institutional_actions", "Institutional Actions", false],
      ["is_public", "Is Public", true],
    ];
    const toggleRefs = {};
    grid.appendChild(sectionTitle("Flags"));
    toggleDefs.forEach(([key, label, val]) => {
      const { wrap, chk } = toggleField(label, val);
      toggleRefs[key] = chk;
      grid.appendChild(wrap);
    });

    /* schools */
    const { el: schoolsEl, getSchools } = buildSchoolsSection([]);
    grid.appendChild(schoolsEl);

    body.appendChild(grid);
    modal.appendChild(body);

    const footer = document.createElement("div");
    footer.className = "adm-modal-footer";
    const cancelBtn = document.createElement("button");
    cancelBtn.className = "adm-btn-cancel";
    cancelBtn.textContent = "Cancel";
    cancelBtn.addEventListener("click", () => closeModal(overlay));

    const saveBtn = document.createElement("button");
    saveBtn.className = "adm-btn-save";
    saveBtn.textContent = "Create Application";
    saveBtn.addEventListener("click", async () => {
      /* required text fields */
      const requiredText = [
        pseudonymInp,
        aliasInp,
        undergradInp,
        stateInp,
        sesInp,
      ];
      let invalid = false;
      requiredText.forEach((el) => {
        if (!el.value.trim()) {
          el.style.borderColor = "#ef4444";
          if (!invalid) {
            el.focus();
            invalid = true;
          }
        } else {
          el.style.borderColor = "";
        }
      });

      /* required numeric fields (empty check only) */
      [cycleStartInp, cycleEndInp].forEach((el) => {
        if (el.value === "") {
          el.style.borderColor = "#ef4444";
          if (!invalid) {
            el.focus();
            invalid = true;
          }
        } else {
          el.style.borderColor = "";
        }
      });

      /* GPA: required, 0.00 – 4.00 */
      const gpaVal = parseFloat(gpaInp.value);
      if (gpaInp.value === "" || isNaN(gpaVal) || gpaVal < 0 || gpaVal > 4.0) {
        gpaInp.style.borderColor = "#ef4444";
        gpaInp.title = "GPA must be between 0.00 and 4.00";
        if (!invalid) {
          gpaInp.focus();
          invalid = true;
        }
      } else {
        gpaInp.style.borderColor = "";
        gpaInp.title = "";
      }

      /* MCAT: required, 472 – 528 */
      const mcatVal = parseInt(mcatInp.value, 10);
      if (
        mcatInp.value === "" ||
        isNaN(mcatVal) ||
        mcatVal < 472 ||
        mcatVal > 528
      ) {
        mcatInp.style.borderColor = "#ef4444";
        mcatInp.title = "MCAT must be between 472 and 528";
        if (!invalid) {
          mcatInp.focus();
          invalid = true;
        }
      } else {
        mcatInp.style.borderColor = "";
        mcatInp.title = "";
      }

      if (invalid) return;

      saveBtn.disabled = true;
      saveBtn.textContent = "Creating…";

      const payload = {};
      Object.entries(fields).forEach(([k, el]) => {
        payload[k] =
          el.tagName === "SELECT"
            ? el.value
            : el.value === ""
              ? null
              : el.value;
      });
      Object.entries(toggleRefs).forEach(([k, chk]) => {
        payload[k] = chk.checked;
      });
      ["gpa"].forEach((k) => {
        if (payload[k] !== null) payload[k] = parseFloat(payload[k]);
      });
      [
        "mcat",
        "gap_years",
        "interviews_count",
        "acceptances_count",
        "scholarships_count",
        "application_cycle_start_year",
        "application_cycle_end_year",
      ].forEach((k) => {
        if (payload[k] !== null) payload[k] = parseInt(payload[k], 10);
      });

      const result = await callCreate(CREATE_APPLICATION_URL, payload);
      if (result) {
        const newApp = result.application || result;
        const schools = getSchools();
        if (schools.length && newApp.id) {
          const schoolsResult = await callManageSchools(newApp.id, schools);
          if (schoolsResult)
            newApp.application_schools = schoolsResult.schools || [];
        }
        allApplications.unshift(newApp);
        appPage = 1;
        renderApplicationsTable();
        closeModal(overlay);
      } else {
        saveBtn.disabled = false;
        saveBtn.textContent = "Create Application";
        alert("Failed to create. Please try again.");
      }
    });

    footer.appendChild(cancelBtn);
    footer.appendChild(saveBtn);
    modal.appendChild(footer);
    openModal(overlay);
  }

  /* ── Add New Experience modal ────────────────────────────────────────────── */
  function openNewExpModal() {
    const overlay = buildModalOverlay("adm-new-exp-modal");
    const modal = overlay.querySelector(".adm-modal");

    modal.innerHTML = `
        <div class="adm-modal-header">
          <span class="adm-modal-title">Add New Experience</span>
          <button class="adm-modal-close" aria-label="Close">&times;</button>
        </div>`;
    modal
      .querySelector(".adm-modal-close")
      .addEventListener("click", () => closeModal(overlay));

    const body = document.createElement("div");
    body.className = "adm-modal-body";
    const grid = document.createElement("div");
    grid.className = "adm-form-grid";

    /* application picker */
    const appOptions = [["", "— Select application —"]].concat(
      allApplications.map((a) => [a.id, a.pseudonym || a.alias || a.id]),
    );
    const appPickerSel = sel(appOptions, "");

    const titleInp = inp("text");
    const typeInp = inp("text");
    const categorySel = sel(
      [
        ["", "— Select type —"],
        ["additional", "Additional"],
        ["most_meaningful", "Most Meaningful"],
      ],
      "",
    );
    const hoursInp = inp("number", 0, null, "0");
    const descEl = document.createElement("textarea");
    descEl.className = "adm-textarea";
    descEl.rows = 5;

    grid.appendChild(buildField("Application (Student) *", appPickerSel, true));
    grid.appendChild(buildField("Title *", titleInp, true));
    grid.appendChild(buildField("Category *", typeInp));
    grid.appendChild(buildField("Type *", categorySel));
    grid.appendChild(buildField("Hours", hoursInp));
    grid.appendChild(buildField("Description", descEl, true));

    body.appendChild(grid);
    modal.appendChild(body);

    const footer = document.createElement("div");
    footer.className = "adm-modal-footer";
    const cancelBtn = document.createElement("button");
    cancelBtn.className = "adm-btn-cancel";
    cancelBtn.textContent = "Cancel";
    cancelBtn.addEventListener("click", () => closeModal(overlay));

    const saveBtn = document.createElement("button");
    saveBtn.className = "adm-btn-save";
    saveBtn.textContent = "Create Experience";
    saveBtn.addEventListener("click", async () => {
      /* required field validation */
      let invalid = false;
      [appPickerSel, titleInp, typeInp, categorySel].forEach((el) => {
        if (!el.value || !el.value.trim()) {
          el.style.borderColor = "#ef4444";
          if (!invalid) {
            el.focus();
            invalid = true;
          }
        } else {
          el.style.borderColor = "";
        }
      });
      if (invalid) return;

      saveBtn.disabled = true;
      saveBtn.textContent = "Creating…";

      const parentApp = allApplications.find(
        (a) => a.id === appPickerSel.value,
      );

      /* auto sort_order: max existing sort_order for this application + 1, min 1 */
      const siblingExps = allExperiences.filter(
        (e) => e.application_id === appPickerSel.value,
      );
      const maxSort = siblingExps.reduce(
        (max, e) => Math.max(max, e.sort_order || 0),
        0,
      );
      const nextSort = maxSort + 1;

      const payload = {
        application_id: appPickerSel.value,
        title: titleInp.value || null,
        experience_type: typeInp.value || null,
        category: categorySel.value || null,
        hours: hoursInp.value !== "" ? parseInt(hoursInp.value, 10) : null,
        sort_order: nextSort,
        description: descEl.value || null,
      };

      const result = await callCreate(CREATE_EXPERIENCE_URL, payload);
      if (result) {
        const newExp = {
          ...(result.experience || result),
          student_name: parentApp
            ? parentApp.pseudonym || parentApp.alias || "-"
            : "-",
        };
        allExperiences.unshift(newExp);
        expPage = 1;
        renderExperiencesTable();
        closeModal(overlay);
      } else {
        saveBtn.disabled = false;
        saveBtn.textContent = "Create Experience";
        alert("Failed to create. Please try again.");
      }
    });

    footer.appendChild(cancelBtn);
    footer.appendChild(saveBtn);
    modal.appendChild(footer);
    openModal(overlay);
  }

  /* ── Init ────────────────────────────────────────────────────────────────── */
  function renderSidebarUserName(user) {
    var safeUser = user || {};
    var name =
      (safeUser.name && safeUser.name.trim()) ||
      (safeUser.full_name && safeUser.full_name.trim()) ||
      [safeUser.first_name, safeUser.last_name]
        .filter(Boolean)
        .join(" ")
        .trim() ||
      (safeUser.email && safeUser.email.trim()) ||
      "User Name";

    document
      .querySelectorAll('[data-field="current-user-name"]')
      .forEach(function (el) {
        el.textContent = name;
      });
  }

  function injectAdminSidebarLink() {
    if (document.getElementById("sidebar-admin-link")) return;

    var ADMIN_ICON =
      '<svg xmlns="http://www.w3.org/2000/svg" width="25" height="25" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>';
    var link = document.createElement("a");
    link.id = "sidebar-admin-link";
    link.className = "sidebar-admin-link";
    link.href = "/portal-admin";
    link.innerHTML =
      ADMIN_ICON +
      '<span class="sidebar-text sidebar-admin-link-text">Admin Dashboard</span>';

    var sidebarNav = document.querySelector(".sidebar-nav");
    if (sidebarNav) {
      sidebarNav.appendChild(link);
      return;
    }

    var sidebar = document.querySelector(".sidebar");
    if (sidebar) sidebar.appendChild(link);
  }

  async function initPortalTables() {
    const applications = await fetchApplications();
    allApplications = applications;
    allExperiences = applications.flatMap((app) =>
      (Array.isArray(app.application_experiences)
        ? app.application_experiences
        : []
      ).map((exp) => ({
        ...exp,
        pseudonym: app.pseudonym || "-",
        student_name: app.pseudonym || "-",
      })),
    );

    appPage = 1;
    expPage = 1;
    renderApplicationsTable();
    renderExperiencesTable();
  }

  /* Expose globally so Webflow onclick attributes can call them directly */
  window.openNewAppModal = openNewAppModal;
  window.openNewExpModal = openNewExpModal;

  document.addEventListener("DOMContentLoaded", function () {
    /* ── Role guard ─────────────────────────────────────────────────────────── */
    var portalUser = {};
    try {
      portalUser = JSON.parse(localStorage.getItem("portal_user") || "{}");
      if (!portalUser || portalUser.role !== "admin") {
        window.location.replace("/portal");
        return;
      }
    } catch (_) {
      window.location.replace("/portal");
      return;
    }
    renderSidebarUserName(portalUser);
    injectAdminSidebarLink();

    /* ── Wire "Add New" buttons ─────────────────────────────────────────────
         Primary:  data-action="new-application" / data-action="new-experience"
         Fallback: any clickable element whose visible text matches             */
    function wireAddNew(selector, textMatch, handler) {
      let found = false;
      document.querySelectorAll(selector).forEach((el) => {
        el.addEventListener("click", (e) => {
          e.preventDefault();
          e.stopPropagation();
          handler();
        });
        found = true;
      });
      if (!found) {
        document
          .querySelectorAll("a, button, div[role='button'], .w-button")
          .forEach((el) => {
            if (el.textContent.trim().toLowerCase().includes(textMatch)) {
              el.addEventListener("click", (e) => {
                e.preventDefault();
                e.stopPropagation();
                handler();
              });
            }
          });
      }
    }

    wireAddNew(
      '[data-action="new-application"]',
      "add new application",
      openNewAppModal,
    );
    wireAddNew(
      '[data-action="new-experience"]',
      "add new experience",
      openNewExpModal,
    );

    initAdminSearchHandlers();
    injectCsvUploadButton();
    initPortalTables();
  });

  function getSearchTextFromScope(scopeEl) {
    if (!scopeEl) return "";
    const input = scopeEl.querySelector(
      'input[type="search"], input[type="text"]',
    );
    if (!input) return "";
    return input.value.trim().toLowerCase();
  }

  function getAdminSearchTextForTab(tabType) {
    if (tabType === "experiences") {
      const expForm = document.querySelector(
        'form[data-search-form="experiences"]',
      );
      return getSearchTextFromScope(expForm);
    }
    const normalForm = document.querySelector(
      'form[data-search-form="normal"]',
    );
    const sidebarForm = document.querySelector(
      'form[data-search-form="sidebar-normal"]',
    );
    return (
      getSearchTextFromScope(normalForm) ||
      getSearchTextFromScope(sidebarForm) ||
      ""
    );
  }

  function applicationMatchesSearch(app, searchText) {
    if (!searchText) return true;
    const searchableValues = [
      app.pseudonym,
      app.alias,
      app.undergrad_institution,
      app.state,
      app.gpa,
      app.mcat,
      app.gap_years,
      app.interviews_count,
    ].map(function (value) {
      return String(value != null ? value : "").toLowerCase();
    });
    return searchableValues.some(function (value) {
      return value.includes(searchText);
    });
  }

  function experienceMatchesSearch(exp, searchText) {
    if (!searchText) return true;
    const searchableValues = [
      exp.student_name,
      exp.pseudonym,
      exp.title,
      exp.experience_type,
      exp.category,
      exp.hours,
    ].map(function (value) {
      return String(value != null ? value : "").toLowerCase();
    });
    return searchableValues.some(function (value) {
      return value.includes(searchText);
    });
  }

  function filterApplicationsBySearch(applications, searchText) {
    if (!searchText) return applications;
    return applications.filter(function (app) {
      return applicationMatchesSearch(app, searchText);
    });
  }

  function filterExperiencesBySearch(experiences, searchText) {
    if (!searchText) return experiences;
    return experiences.filter(function (exp) {
      return experienceMatchesSearch(exp, searchText);
    });
  }

  function getFilteredApplicationsForCurrentSearch() {
    return filterApplicationsBySearch(
      allApplications,
      getAdminSearchTextForTab("normal"),
    );
  }

  function getFilteredExperiencesForCurrentSearch() {
    return filterExperiencesBySearch(
      allExperiences,
      getAdminSearchTextForTab("experiences"),
    );
  }

  function runAdminFrontendSearch(tabType) {
    if (tabType === "experiences") {
      expPage = 1;
      renderExperiencesTable();
      return;
    }
    appPage = 1;
    renderApplicationsTable();
  }

  function rerunAdminSearchFromForm(form) {
    if (!(form instanceof HTMLFormElement)) return;
    const searchType = form.getAttribute("data-search-form");
    if (!searchType) return;
    const tabType = searchType === "experiences" ? "experiences" : "normal";
    runAdminFrontendSearch(tabType);
  }

  function initAdminSearchHandlers() {
    document.addEventListener("click", function (e) {
      const normalSearchBtn = e.target.closest('[data-action="search-normal"]');
      const expSearchBtn = e.target.closest(
        '[data-action="search-experiences"], [data-action="search-favorite"]',
      );

      if (normalSearchBtn) {
        runAdminFrontendSearch("normal");
        return;
      }

      if (expSearchBtn) {
        runAdminFrontendSearch("experiences");
      }
    });

    document.addEventListener("submit", function (e) {
      const form = e.target;
      if (!(form instanceof HTMLFormElement)) return;
      const searchType = form.getAttribute("data-search-form");
      if (!searchType) return;
      e.preventDefault();
      rerunAdminSearchFromForm(form);
    });

    document.addEventListener("input", function (e) {
      const target = e.target;
      if (!(target instanceof HTMLInputElement)) return;
      if (target.type !== "search" && target.type !== "text") return;
      const form = target.closest("form");
      if (!(form instanceof HTMLFormElement)) return;
      const searchType = form.getAttribute("data-search-form");
      if (!searchType) return;
      if (target.value.trim() === "") rerunAdminSearchFromForm(form);
    });

    document.addEventListener(
      "keydown",
      function (e) {
        if (e.key !== "Enter") return;
        const target = e.target;
        if (!(target instanceof HTMLInputElement)) return;
        if (target.type !== "search" && target.type !== "text") return;
        const form = target.closest("form");
        if (!(form instanceof HTMLFormElement)) return;
        const searchType = form.getAttribute("data-search-form");
        if (!searchType) return;
        e.preventDefault();
        e.stopPropagation();
        rerunAdminSearchFromForm(form);
      },
      true,
    );
  }

  function findAddNewButton(kind) {
    const actionSelector =
      kind === "experiences"
        ? '[data-action="new-experience"]'
        : '[data-action="new-application"]';
    const byAction = document.querySelector(actionSelector);
    if (byAction) return byAction;

    const clickables = document.querySelectorAll(
      "a, button, div[role='button'], .w-button",
    );
    const wanted =
      kind === "experiences"
        ? ["add new experience", "new experience"]
        : ["add new application", "add new"];

    for (let i = 0; i < clickables.length; i++) {
      const el = clickables[i];
      const text = (el.textContent || "").trim().toLowerCase();
      if (wanted.some((w) => text.includes(w))) return el;
    }
    return null;
  }

  function injectCsvUploadButton() {
    injectUploadButtonForType({
      id: "adm-upload-applications-btn",
      label: "Upload Applications",
      kind: "applications",
      endpoint: UPLOAD_APPLICATIONS_FILE_URL,
      addNewButton: findAddNewButton("applications"),
      onSuccess: async function () {
        await initPortalTables();
      },
    });

    injectUploadButtonForType({
      id: "adm-upload-experiences-btn",
      label: "Upload Experiences",
      kind: "experiences",
      endpoint: UPLOAD_EXPERIENCES_FILE_URL,
      addNewButton: findAddNewButton("experiences"),
      onSuccess: async function () {
        await initPortalTables();
      },
    });
  }

  function injectUploadButtonForType(config) {
    if (document.getElementById(config.id)) return;
    const addNewBtn = config.addNewButton;
    if (!addNewBtn || !addNewBtn.parentElement) return;

    const uploadBtn = document.createElement("button");
    uploadBtn.id = config.id;
    uploadBtn.type = "button";
    uploadBtn.textContent = config.label;
    uploadBtn.className = addNewBtn.className || "";
    uploadBtn.style.marginLeft = "8px";

    const fileInput = document.createElement("input");
    fileInput.type = "file";
    fileInput.accept =
      ".csv,text/csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet,.xls,.xlsx";
    fileInput.style.display = "none";

    uploadBtn.addEventListener("click", function (e) {
      e.preventDefault();
      e.stopPropagation();
      fileInput.click();
    });

    fileInput.addEventListener("change", async function () {
      const file = fileInput.files && fileInput.files[0];
      fileInput.value = "";
      if (!file) return;

      uploadBtn.disabled = true;
      const originalText = uploadBtn.textContent;
      uploadBtn.textContent = "Uploading...";
      try {
        const result = await uploadSpreadsheetFile(file, config.endpoint);
        if (config.onSuccess) await config.onSuccess(result);
        const failed = Number(result && result.failed ? result.failed : 0);
        if (failed > 0) {
          const firstError =
            Array.isArray(result.errors) && result.errors.length
              ? result.errors[0]
              : null;
          const firstErrorText = firstError
            ? " First error row " +
              firstError.row +
              ": " +
              (firstError.error || "Unknown error")
            : "";
          alert(
            "Upload finished with issues. Inserted: " +
              (result.inserted || 0) +
              ", Failed: " +
              failed +
              "." +
              firstErrorText,
          );
        } else {
          alert(
            "Upload successful. Inserted: " +
              (result && result.inserted ? result.inserted : 0),
          );
        }
      } catch (error) {
        alert(
          error && error.message
            ? error.message
            : "Failed to upload spreadsheet file.",
        );
      } finally {
        uploadBtn.disabled = false;
        uploadBtn.textContent = originalText;
      }
    });

    addNewBtn.insertAdjacentElement("afterend", uploadBtn);
    document.body.appendChild(fileInput);
  }

  async function uploadSpreadsheetFile(file, endpointUrl) {
    const formData = new FormData();
    formData.append("file", file);

    const res = await fetch(endpointUrl, {
      method: "POST",
      headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: "Bearer " + SUPABASE_ANON_KEY,
      },
      body: formData,
    });

    let responseJson = null;
    try {
      responseJson = await res.json();
    } catch (_) {
      responseJson = null;
    }

    if (res.ok)
      return responseJson || { success: true, inserted: 0, failed: 0 };

    let message = "Failed to upload spreadsheet file.";
    try {
      const errorJson = responseJson || {};
      message = buildFriendlyUploadError(errorJson);
    } catch (_) {
      try {
        const errorText = await res.text();
        if (errorText) message = errorText;
      } catch (_) {}
    }
    throw new Error(message);
  }

  function buildFriendlyUploadError(errorJson) {
    if (!errorJson || typeof errorJson !== "object") {
      return "Upload failed. Please check your file format and required columns.";
    }

    const topLevelMessage = errorJson.message || errorJson.error;
    const errors = Array.isArray(errorJson.errors) ? errorJson.errors : [];

    if (!errors.length) {
      return (
        topLevelMessage ||
        "Upload failed. Please check your file format and required columns."
      );
    }

    const lines = errors.slice(0, 6).map(function (item) {
      const rowLabel =
        item && item.row !== undefined && item.row !== null
          ? "Row " + item.row
          : "Row ?";
      const raw = String(item && item.error ? item.error : "Invalid value");
      return rowLabel + ": " + normalizeUploadErrorMessage(raw);
    });

    if (errors.length > 6) {
      lines.push("...and " + (errors.length - 6) + " more row errors.");
    }

    return lines.join("\n");
  }

  function normalizeUploadErrorMessage(raw) {
    const msg = String(raw || "").trim();
    const lower = msg.toLowerCase();

    if (lower.includes("invalid app cycle format")) {
      return "App Cycle must look like 2023-2024.";
    }
    if (lower.includes("pseudonym is required")) {
      return "Missing required field: Pseudonym.";
    }
    if (lower.includes("title is required")) {
      return "Missing required field: Title.";
    }
    if (lower.includes("experience_type is required")) {
      return "Missing required field: Experience Type.";
    }
    if (lower.includes("could not resolve application_id")) {
      return "Applicant not found. Provide a valid application_id or matching Pseudonym/Alias.";
    }
    if (lower.includes("application_experiences_application_id_fkey")) {
      return "Invalid application_id (no matching application record).";
    }

    return msg;
  }
})();
